using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    // ── ChargeAsync ─────────────────────────────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ReturnsUniqueChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_visa_1", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_visa_2", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-100.50)]
    public async Task ChargeAsync_NonPositiveAmount_ThrowsArgumentException(double amount)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("tok_valid", (decimal)amount));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_InvalidToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_MinimumAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    // ── RefundAsync ─────────────────────────────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var charge = await _gateway.ChargeAsync("tok_valid", 25.00m);

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_InvalidChargeId_ThrowsArgumentException(string? chargeId)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(chargeId!));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_DuplicateRefund_ReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid", 50.00m);
        await _gateway.RefundAsync(charge.ChargeId);

        var duplicate = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsFalse(duplicate.Success);
    }

    [TestMethod]
    public async Task RefundAsync_ReturnsUniqueRefundIds()
    {
        var charge1 = await _gateway.ChargeAsync("tok_1", 10.00m);
        var charge2 = await _gateway.ChargeAsync("tok_2", 20.00m);

        var refund1 = await _gateway.RefundAsync(charge1.ChargeId);
        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);

        Assert.AreNotEqual(refund1.RefundId, refund2.RefundId);
    }
}

